module piso_shift_register (CLK, RST, LOAD, D, Q);
input CLK, RST, LOAD;
input [7:0] D;
output reg Q;
reg [7:0] data_buffer;

always @(posedge CLK or posedge RST) begin
    if (RST)
        data_buffer <= 8'b00000000;
    else if (LOAD)
        data_buffer <= D;
    else
        data_buffer <= data_buffer >> 1;
end

always @(*) begin
    Q = data_buffer[0];
end

endmodule
